// Assemble a layer-snapshot v1.0.0 document (see docs/layer-snapshot-contract.md).
const bundle = $input.first().json.bundle;
const now = new Date();
const iso = (d) => new Date(d).toISOString().replace(/\.\d{3}Z$/, 'Z');

const LAYERS = {
  weather:     { label: 'Weather', kind: 'timeseries', source_id: 'open-meteo' },
  air_quality: { label: 'Air quality', kind: 'timeseries', source_id: 'open-meteo-air-quality' },
  fires:       { label: 'Fires / thermal anomalies', kind: 'events', source_id: 'nasa-firms' },
  earthquakes: { label: 'Earthquakes', kind: 'events', source_id: 'usgs-earthquakes' },
  pois:        { label: 'Points of interest', kind: 'static', source_id: 'osm-overpass' },
};

// Honest per-source status from the latest runs.
const sourceStatus = (bundle.sources ?? []).map((s) => {
  let status = 'error';
  if (!s.enabled) status = 'disabled';
  else if (s.last_run_status === 'error') status = 'error';
  else if (s.last_success_at) {
    const ageMin = (now - new Date(s.last_success_at)) / 60000;
    status = ageMin <= s.freshness_window_minutes ? 'ok' : 'stale';
  }
  return {
    source_id: s.source_id, name: s.name, url: s.url, license: s.license,
    status, mode: 'live',
    last_success_at: s.last_success_at ? iso(s.last_success_at) : null,
    last_error: s.last_error ?? null,
  };
});
const statusBySource = Object.fromEntries(sourceStatus.map((s) => [s.source_id, s]));

// Group observations into features per layer.
const layers = {};
for (const [layerId, def] of Object.entries(LAYERS)) {
  const obs = (bundle.observations ?? []).filter((o) => o.layer === layerId);
  const byFeature = new Map();
  for (const o of obs) {
    if (!byFeature.has(o.external_ref)) {
      byFeature.set(o.external_ref, {
        id: o.external_ref, name: o.entity_name ?? o.values.place ?? o.external_ref,
        lon: o.lon, lat: o.lat, observations: [],
      });
    }
    byFeature.get(o.external_ref).observations.push({ observed_at: iso(o.observed_at), values: o.values });
  }
  const src = statusBySource[def.source_id];
  const features = [...byFeature.values()];
  let status = src?.status ?? 'error';
  if (status === 'ok' && features.length === 0) status = 'ok_empty';
  layers[layerId] = {
    id: layerId, label: def.label, kind: def.kind, source_id: def.source_id,
    status, last_updated: src?.last_success_at ?? iso(now), features,
  };
}

const snapshot = {
  contract: 'layer-snapshot',
  contract_version: '1.0.0',
  snapshot_id: `live-rosario-${iso(now)}`,
  generated_at: iso(now),
  mode: 'live',
  region: {
    name: 'Rosario / Gran Rosario / Paraná corridor / Villa Constitución',
    bbox: [-60.95, -33.35, -60.20, -32.55],
  },
  time_range: {
    start: iso(new Date(now - 24 * 3600 * 1000)),
    end: iso(now),
    step_minutes: 60,
  },
  layers,
  source_status: sourceStatus,
};
return [{ json: { snapshot } }];

