INSERT INTO digital_twin.layer_snapshots (snapshot_id, contract_version, mode, generated_at, time_start, time_end, payload)
VALUES ($1, $2, 'live', $3::timestamptz, $4::timestamptz, $5::timestamptz, $6::jsonb)
ON CONFLICT (snapshot_id) DO UPDATE SET payload = EXCLUDED.payload;
